func isReplaceableProviderOutcomeReason(reason string) bool {
	switch strings.TrimSpace(reason) {
	case "",
		"timeout",
		"transport",
		"quota",
		"routing",
		agent.FailureModeAuthError,
		agent.FailureModeServerUnavailable,
