}

// seedClosedBead writes a closed bead into the store and returns its id.
func seedClosedBead(t *testing.T, store *bead.Store, title string) string {
	t.Helper()
	b := &bead.Bead{Title: title, Status: bead.StatusOpen}
	if err := store.Create(context.Background(), b); err != nil {
		t.Fatalf("create bead: %v", err)
	}
	if err := store.UpdateWithLifecycleStatus(b.ID, bead.StatusClosed, bead.LifecycleTransitionOptions{
		ManualClose: true,
		Reason:      "test close",
		Source:      "test",
	}, func(x *bead.Bead) error {
		x.Owner = "agent-prior"
		return nil
	}); err != nil {
		t.Fatalf("close bead: %v", err)
	}
	return b.ID
}

