	}
	if cfg.Library == nil || cfg.Library.Path == "" {
		return ""
	}
	p := cfg.Library.Path
	if !filepath.IsAbs(p) {
		p = filepath.Join(workingDir, p)
	}
	if _, err := os.Stat(p); err != nil {
		return ""
	}
	return p
