	require.Len(t, entries, 1)
	assert.Equal(t, "ddx-eligible", entries[0].BeadID)
	assert.Equal(t, FilterDecisionNext, entries[0].FilterDecision)
}

// TestPreviewQueue_DepsBlocked verifies that a bead with an unclosed
