	beforeClaim func()
}

func (s *claimCountingStore) Claim(id, assignee string) error {
	if s.beforeClaim != nil {
		s.beforeClaim()
	}
	atomic.AddInt32(&s.claimCalls, 1)
	return s.Store.Claim(id, assignee)
}

