// GetBeadSnapshots implements ddxgraphql.StateProvider.
//
// When projectID is non-empty this delegates to GetBeadSnapshotsForProject so
// the resolver path opens exactly one project's store; a scoped query never
// pays the N-project scan cost (ddx-9ce6842a Part 2 step 1). When projectID is
// empty every registered project is scanned — that is still O(projects) by
// necessity, but each project's bead.Store receives a pushed-down filter so
// non-matching beads are never materialized as BeadSnapshot values.
func (s *ServerState) GetBeadSnapshots(status, label, projectID, search string) []ddxgraphql.BeadSnapshot {
	if projectID != "" {
		return s.GetBeadSnapshotsForProject(projectID, status, label, search)
	}
	projects := s.GetProjects()
	pred := beadFilterPredicate(status, label, search)
	var result []ddxgraphql.BeadSnapshot
	for _, proj := range projects {
		result = append(result, s.beadSnapshotsForProjectEntry(proj, pred)...)
	}
	return result
}

// GetBeadSnapshotsForProject implements ddxgraphql.StateProvider. It opens
// exactly one project's bead store — iteration over other projects is not
// performed for any reason, so the cross-project loop cost is avoided for the
// common per-project bead list.
func (s *ServerState) GetBeadSnapshotsForProject(projectID, status, label, search string) []ddxgraphql.BeadSnapshot {
	if projectID == "" {
		return nil
	}
	proj, ok := s.GetProjectByID(projectID)
	if !ok {
		return nil
	}
	pred := beadFilterPredicate(status, label, search)
	return s.beadSnapshotsForProjectEntry(proj, pred)
}

// beadStoreOpenHook is a test-only hook: when non-nil, every call to
// beadSnapshotsForProjectEntry invokes it with the project path it is about
// to open. Tests use this to assert that the scoped path opens exactly one
// project's store (ddx-9ce6842a AC §3).
var beadStoreOpenHook func(projectPath string)

// beadSnapshotsForProjectEntry reads the single project's bead store, applies
// the (possibly nil) predicate at the store layer (filter pushdown), and
// returns GraphQL snapshots for the matching beads. Callers are responsible
// for deciding which projects to pass through — this helper never touches any
// other project's state.
func (s *ServerState) beadSnapshotsForProjectEntry(proj ProjectEntry, pred func(bead.Bead) bool) []ddxgraphql.BeadSnapshot {
	if beadStoreOpenHook != nil {
		beadStoreOpenHook(proj.Path)
	}
	store := bead.NewStore(ddxroot.JoinProject(proj.Path))
	beads, err := store.ReadAllFiltered(context.Background(), pred)
	if err != nil {
		return nil
	}
	out := make([]ddxgraphql.BeadSnapshot, 0, len(beads))
	for _, b := range beads {
		snap := beadSnapshotFromStoreBead(proj.ID, b)
		s.rememberBeadLocation(b.ID, proj, &snap)
		out = append(out, snap)
	}
	return out
}

// beadFilterPredicate returns a predicate suitable for bead.Store.ReadAllFiltered
// that applies status/label/search filters. A nil return means "match all".
func beadFilterPredicate(status, label, search string) func(bead.Bead) bool {
	if status == "" && label == "" && search == "" {
		return nil
	}
	q := strings.ToLower(search)
	return func(b bead.Bead) bool {
		if status != "" && b.Status != status {
			return false
		}
		if label != "" && !containsString(b.Labels, label) {
			return false
		}
		if q != "" {
			if !strings.Contains(strings.ToLower(b.ID), q) && !strings.Contains(strings.ToLower(b.Title), q) {
				return false
			}
		}
		return true
	}
}

// GetBeadSnapshot implements ddxgraphql.StateProvider.
func (s *ServerState) GetBeadSnapshot(id string) (*ddxgraphql.BeadSnapshot, bool) {
	if id == "" {
		return nil, false
	}

	if loc, ok := s.lookupBeadLocation(id); ok {
		if loc.Snapshot != nil && isCacheValid(loc) {
			return loc.Snapshot, true
		}
		proj := ProjectEntry{ID: loc.ProjectID, Path: loc.ProjectPath}
		if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
			s.rememberBeadLocation(id, proj, snap)
			return snap, true
		}
		s.forgetBeadLocation(id)
	}

	for _, proj := range s.GetProjects() {
		if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
			s.rememberBeadLocation(id, proj, snap)
			return snap, true
		}
	}
	return nil, false
}

func isCacheValid(entry beadIndexEntry) bool {
	if entry.Snapshot == nil || entry.SnapshotMtimeNs == 0 {
		return false
	}
	beadPath := filepath.Join(entry.ProjectPath, ddxroot.DirName, "beads", entry.Snapshot.ID+".jsonl")
	info, err := os.Stat(beadPath)
	if err != nil {
		return false
	}
	return info.ModTime().UnixNano() == entry.SnapshotMtimeNs
}

func (s *ServerState) rememberBeadLocation(id string, proj ProjectEntry, snapshots ...*ddxgraphql.BeadSnapshot) {
	if id == "" || proj.ID == "" || proj.Path == "" {
		return
	}
	s.beadIndexMu.Lock()
	defer s.beadIndexMu.Unlock()
	if s.beadIndex == nil {
		s.beadIndex = make(map[string]beadIndexEntry)
	}
	entry := beadIndexEntry{ProjectID: proj.ID, ProjectPath: proj.Path}
	if len(snapshots) > 0 && snapshots[0] != nil {
		entry.Snapshot = snapshots[0]
		beadPath := filepath.Join(proj.Path, ddxroot.DirName, "beads", snapshots[0].ID+".jsonl")
		if info, err := os.Stat(beadPath); err == nil {
			entry.SnapshotMtimeNs = info.ModTime().UnixNano()
		}
	}
	s.beadIndex[id] = entry
}

func (s *ServerState) lookupBeadLocation(id string) (beadIndexEntry, bool) {
	s.beadIndexMu.RLock()
	defer s.beadIndexMu.RUnlock()
	if s.beadIndex == nil {
		return beadIndexEntry{}, false
	}
	loc, ok := s.beadIndex[id]
	return loc, ok
}

func (s *ServerState) forgetBeadLocation(id string) {
	s.beadIndexMu.Lock()
	defer s.beadIndexMu.Unlock()
	delete(s.beadIndex, id)
}

func readBeadSnapshotFromProject(proj ProjectEntry, id string) (*ddxgraphql.BeadSnapshot, bool) {
	store := bead.NewStore(ddxroot.JoinProject(proj.Path))
	b, err := store.Get(context.Background(), id)
	if err != nil {
		return nil, false
	}
	snap := beadSnapshotFromStoreBead(proj.ID, *b)
	return &snap, true
}

func beadSnapshotFromStoreBead(projectID string, b bead.Bead) ddxgraphql.BeadSnapshot {
	snap := ddxgraphql.BeadSnapshot{
		ProjectID:   projectID,
		ID:          b.ID,
		Title:       b.Title,
		Status:      b.Status,
		Priority:    b.Priority,
		IssueType:   b.IssueType,
		Owner:       b.Owner,

package bead

import (
	"context"
	"io"
)

// RawBackend is the low-level storage contract — read/write the entire bead
// corpus and serialize concurrent rewrites. JSONLBackend and ExternalBackend
// implement it. New backends should implement Backend directly; RawBackend is
// retained for the JSONL/external composition path that Store uses internally.
// Higher-level operations (CRUD, claim, ready/blocked, dep ops, events,
// archive, JSONL interchange) live on the Backend interface below and are
// composed on top of a RawBackend by Store.
type RawBackend interface {
	Init() error
	ReadAll() ([]Bead, error)
	WriteAll(beads []Bead) error
	WithLock(fn func() error) error
}

// Backend is the high-level bead-tracker contract that callers in
// cli/cmd and the agent/server helpers program against. It composes the
// current store surface into capability-sized pieces so callers can depend on
// the narrowest interface that fits their use case.
//
// *Store satisfies this interface; the JSONL implementation lives in store.go
// and delegates per-write serialization to the configured RawBackend
// (JSONLBackend by default, ExternalBackend when DDX_BEAD_BACKEND or the
// .ddx/config.yaml beads.backend field selects bd/br).
//
// chaos_test.go and other conformance suites should program against these
// interfaces so additional backends can be exercised by the same tests.
type Backend interface {
	BeadInitializer
	BeadReader
	BeadLifecycle
	BeadEventReader
	BeadEventWriter
	BeadQueries
	BeadDependencyReader
	BeadDependencyWriter
	BeadArchive
	BeadInterchangeReader
	BeadInterchangeWriter
}

// TD-027 foundation interfaces. These are additive and intentionally mirror
// the live Store-backed surface used by callers in this bead slice.
type BeadInitializer interface {
	Init(ctx context.Context) error
}

type BeadReader interface {
	ReadAll(ctx context.Context) ([]Bead, error)
	ReadAllFiltered(ctx context.Context, pred func(Bead) bool) ([]Bead, error)
	Get(ctx context.Context, id string) (*Bead, error)
}

type BeadLifecycle interface {
	Create(ctx context.Context, b *Bead) error
	Apply(id string, op Operation) error
}

type BeadEventReader interface {
	Events(ctx context.Context, id string) ([]BeadEvent, error)
	EventsByKind(ctx context.Context, id, kind string) ([]BeadEvent, error)
}

type BeadEventWriter interface {
	AppendEvent(ctx context.Context, id string, event BeadEvent) error
}

type BeadQueries interface {
	List(status, label string, where map[string]string) ([]Bead, error)
	Ready() ([]Bead, error)
	Blocked() ([]Bead, error)
	ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error)
	ProposedOperatorAttention() ([]Bead, error)
	NeedsHuman() ([]Bead, error)
	ExternalBlocked() ([]Bead, error)
	DependencyWaiting() ([]Bead, error)
	BlockedAll() ([]BlockedBead, error)
	Status() (*StatusCounts, error)
}

type BeadDependencyReader interface {
	DepTree(ctx context.Context, rootID string) (string, error)
}

type BeadDependencyWriter interface {
	DepAdd(ctx context.Context, id, depID string) error
	DepRemove(ctx context.Context, id, depID string) error
}

type BeadArchive interface {
	Archive(ctx context.Context, policy ArchivePolicy) ([]string, error)
	Migrate(ctx context.Context) (MigrateStats, error)
}

type BeadInterchangeReader interface {
	ExportTo(ctx context.Context, w io.Writer) error
}

type BeadInterchangeWriter interface {
	Import(ctx context.Context, source, filePath string) (int, error)
}

type ReadOnlyBackend interface {
	BeadInitializer
	BeadReader
	BeadEventReader
	BeadQueries
	BeadDependencyReader
	BeadInterchangeReader
}

// LifecycleSubscriber is the parallel subscription surface from TD-027.
type LifecycleSubscriber interface {
	SubscribeLifecycle(ctx context.Context, projectID string) (<-chan LifecycleEvent, func(), error)
}

// OperationApplier is an optional fast path for RawBackend implementations
// that can preserve specialized mutation behavior.
type OperationApplier interface {
	Apply(ctx context.Context, id string, op Operation) error
}

