func (s *Server) handleReady(w http.ResponseWriter, r *http.Request) {
	checks := map[string]string{}
	ready := true

	// Check library path
	if s.libraryPath() != "" {
		checks["library"] = "ok"
	} else {
		checks["library"] = "not_configured"
	}

	// Check bead store
	store := s.beadStore()
	if _, err := store.Status(); err != nil {
		checks["beads"] = "error: " + err.Error()
		ready = false
	} else {
		checks["beads"] = "ok"
	}

	// Check doc graph
	if _, err := s.buildDocGraph(); err != nil {
		checks["docgraph"] = "error: " + err.Error()
	} else {
		checks["docgraph"] = "ok"
	}

	status := http.StatusOK
	statusStr := "ready"
	if !ready {
		status = http.StatusServiceUnavailable
		statusStr = "not_ready"
	}
	writeJSON(w, status, map[string]any{
		"status": statusStr,

			visibleIDs[row.BeadID] = struct{}{}
		}
	}
	for _, row := range cycleReport.Beads {
		if row.FirstClosedAt != nil {
			visibleIDs[row.BeadID] = struct{}{}
		}
	}
	for _, row := range reworkReport.Beads {
		if row.FirstClosedAt != nil {
			visibleIDs[row.BeadID] = struct{}{}
		}
	}

	visible := make([]bead.Bead, 0, len(beads))
	for _, b := range beads {
		if _, ok := visibleIDs[b.ID]; !ok {
			continue
		}
		visible = append(visible, b)
	}
	return visible, visibleIDs
}

func (s *Service) beadStore() *bead.Store {
	if s.store != nil {
		return s.store
	}
	dir := ddxroot.JoinProject(s.WorkingDir)
	s.store = bead.NewStore(dir)
	return s.store
}

func (s *Service) sessionIndexPath() string {
	return filepath.Join(agent.ResolveLogDir(s.WorkingDir, agent.DefaultLogDir), "sessions.jsonl")
}

func (s *Service) loadInputs() ([]bead.Bead, []agent.SessionEntry, map[string]agent.SessionEntry, map[string]bool, error) {
	beads, err := s.beadStore().ReadAll(context.Background())
	if err != nil {
		return nil, nil, nil, nil, err
	}
	sessions, sessionCostPresent, err := readSessions(s.sessionIndexPath())
	if err != nil {
		return nil, nil, nil, nil, err
	}
	sessionByID := make(map[string]agent.SessionEntry, len(sessions))
	for _, sess := range sessions {
		sessionByID[sess.ID] = sess
	}
	return beads, sessions, sessionByID, sessionCostPresent, nil

