// WorkerDispatch is the resolver for the workerDispatch field.
func (r *mutationResolver) WorkerDispatch(ctx context.Context, kind string, projectID string, args *string) (*WorkerDispatchResult, error) {
	switch kind {
	case "work":
		if r.Actions == nil {
			return nil, fmt.Errorf("work worker dispatcher is not configured")
		}
		return r.Actions.DispatchWorker(ctx, kind, r.projectRoot(ctx, projectID), args)
	case "realign-specs", "run-checks":
		return &WorkerDispatchResult{
			ID:    "queued-worker-" + slug(kind),
			State: queuedPlaceholderState,
			Kind:  kind,
		}, nil
	default:
		return nil, fmt.Errorf("unsupported worker kind %q", kind)
	}
}

// StartWorker is the resolver for the startWorker field.
//
// SD-024 Stage 1: the resolver flows through config.LoadAndResolve so the
// project's .ddx/config.yaml drives default harness/profile/effort/label
// values when the GraphQL input leaves them unset. Input fields are layered
// onto config as CLIOverrides — when present they win over the on-disk
// values. The resolved values are forwarded to ActionDispatcher (and ultimately
// to runWorker, which re-loads config to drive the loop's durable knobs like
// review_max_retries / no_progress_cooldown / heartbeat_interval). This
// closes the GraphQL bypass where hardcoded "smart"/"medium" defaults
// shadowed the on-disk config.
func (r *mutationResolver) StartWorker(ctx context.Context, input StartWorkerInput) (*WorkerDispatchResult, error) {
	if r.Actions == nil {
		return nil, fmt.Errorf("work worker dispatcher is not configured")
	}
	projectRoot := r.projectRoot(ctx, input.ProjectID)

	overrides := config.CLIOverrides{}
	if input.Harness != nil {
		overrides.Harness = strings.TrimSpace(*input.Harness)
	}
	if input.Profile != nil {
		overrides.Profile = strings.TrimSpace(*input.Profile)
	}
	if input.Effort != nil {
		overrides.Effort = strings.TrimSpace(*input.Effort)
	}
	rcfg, _ := config.LoadAndResolve(projectRoot, overrides)

	args := map[string]string{}
	if v := rcfg.Harness(); v != "" {
		args["harness"] = v
	}
	profile := rcfg.Profile()
	if profile == "" {
		profile = "smart"
	}
	args["profile"] = profile
	effort := rcfg.Effort()
	if effort == "" {
		effort = "medium"
	}
	args["effort"] = effort

---
	return &gqlerror.Error{
		Message: personaErr.Message,
		Err:     err,
		Extensions: map[string]any{
			"code": personaErr.Type,
		},
	}
}

// QueueSummary is the resolver for the queueSummary field.
// InProgress counts the reconciled active-work snapshot so lifecycle state and
// active execution agree on what is actually running.
func (r *queryResolver) QueueSummary(ctx context.Context, projectID string) (*QueueSummary, error) {
	projectRoot := r.projectRoot(ctx, projectID)
	store := projectBeadStore(projectRoot)
	counts, err := store.Status()
	if err != nil {
		return nil, err
	}

	activeWork, err := activework.Collect(projectRoot, store, time.Now().UTC())
	if err != nil {
		return nil, err
	}

	return &QueueSummary{
		Ready:             counts.Ready,
		Blocked:           counts.ExternalBlocked,
		InProgress:        activeWork.Count,
		OperatorAttention: counts.OperatorAttention,
		DependencyWaiting: counts.DependencyWaiting,
		ExternalBlocked:   counts.ExternalBlocked,
		Cancelled:         counts.Cancelled,
	}, nil
}

// QueueAndWorkersSummary backs the global drain indicator (ddx-b6cf025c).
// Returns zeros — not an error — for unknown or empty projects so the nav
// component can render without special-casing failures.
func (r *queryResolver) QueueAndWorkersSummary(ctx context.Context, projectID string) (*QueueAndWorkersSummary, error) {
	out := &QueueAndWorkersSummary{}
	// Only resolve ready beads when the projectID maps to a real project.
	// Unknown IDs return zeros rather than falling back to WorkingDir so the
	// indicator does not surface an unrelated project's queue depth.
	if r.State != nil {
		if proj, ok := r.State.GetProjectSnapshotByID(projectID); ok && proj.Path != "" {
			store := projectBeadStore(proj.Path)
			if ready, err := store.Ready(); err == nil {
				out.ReadyBeads = len(ready)
			}
		}
		workers := r.State.GetWorkersGraphQL(projectID)
		out.TotalWorkers = len(workers)
		for _, w := range workers {
			if w != nil && w.State == "running" {
				out.RunningWorkers++
			}
		}
	}
	// Surface the optional workers.max_count cap so the UI can pre-emptively
	// disable the `+ Add worker` affordance rather than relying on a server
	// error from workerDispatch (ddx-b6cf025c review finding).
	if cfg, err := config.LoadWithWorkingDir(r.projectRoot(ctx, projectID)); err == nil && cfg != nil && cfg.Workers != nil && cfg.Workers.MaxCount != nil {
		v := *cfg.Workers.MaxCount
		out.MaxCount = &v
	}
	return out, nil
}

