func (s *Server) handleUpdateBead(w http.ResponseWriter, r *http.Request) {
	if !isTrusted(r) {
		writeJSON(w, http.StatusForbidden, map[string]string{"error": "write endpoints are localhost-only"})
		return
	}
	id := r.PathValue("id")
	if id == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "id is required"})
		return
	}

	var req BeadUpdateRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid request body"})
		return
	}

	store := s.beadStoreForRequest(r)
	mutate := func(b *bead.Bead) error {
		return applyBeadUpdateRequest(b, req)
	}
	var err error
	if req.Status != nil {
		err = store.UpdateWithLifecycleStatus(id, *req.Status, bead.LifecycleTransitionOptions{
			Reason: "REST bead update",
			Source: "rest:beadUpdate",
		}, mutate)
	} else {
		err = store.Update(context.Background(), id, func(b *bead.Bead) {
			_ = mutate(b)
		})
	}
	if err != nil {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": err.Error()})
		return
	}

	updated, err := store.Get(r.Context(), id)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
		return
	}
	writeJSON(w, http.StatusOK, updated)
}

func (s *Server) handleClaimBead(w http.ResponseWriter, r *http.Request) {
	if !isTrusted(r) {
		writeJSON(w, http.StatusForbidden, map[string]string{"error": "write endpoints are localhost-only"})
		return
	}
	id := r.PathValue("id")
	if id == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "id is required"})
		return
	}

	var req struct {
		Assignee string `json:"assignee"`
		Session  string `json:"session"`
		Worktree string `json:"worktree"`
	}
	_ = json.NewDecoder(r.Body).Decode(&req)

	store := s.beadStoreForRequest(r)
	if err := store.ClaimWithOptions(id, req.Assignee, req.Session, req.Worktree); err != nil {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": err.Error()})
		return
	}
	writeJSON(w, http.StatusOK, map[string]string{"id": id, "status": "claimed"})
}

func (s *Server) handleUnclaimBead(w http.ResponseWriter, r *http.Request) {
	if !isTrusted(r) {
		writeJSON(w, http.StatusForbidden, map[string]string{"error": "write endpoints are localhost-only"})
		return
	}
	id := r.PathValue("id")
	if id == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "id is required"})
		return
	}

	store := s.beadStoreForRequest(r)
	if err := store.Unclaim(id); err != nil {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": err.Error()})
		return
	}
	writeJSON(w, http.StatusOK, map[string]string{"id": id, "status": "unclaimed"})
}

