package bead

import (
	"context"
	"io"
	"time"
)

// RawBackend is the low-level storage contract — read/write the entire bead
// corpus and serialize concurrent rewrites. JSONLBackend and ExternalBackend
// implement it. New backends should implement Backend directly; RawBackend is
// retained for the JSONL/external composition path that Store uses internally.
// Higher-level operations (CRUD, claim, ready/blocked, dep ops, events,
// archive, JSONL interchange) live on the Backend interface below and are
// composed on top of a RawBackend by Store.
type RawBackend interface {
	Init() error
	ReadAll() ([]Bead, error)
	WriteAll(beads []Bead) error
	WithLock(fn func() error) error
}

// Backend is the high-level bead-tracker contract that callers in
// cli/cmd and the agent/server helpers program against. It composes the
// current store surface into capability-sized pieces so callers can depend on
// the narrowest interface that fits their use case.
//
// *Store satisfies this interface; the JSONL implementation lives in store.go
// and delegates per-write serialization to the configured RawBackend
// (JSONLBackend by default, ExternalBackend when DDX_BEAD_BACKEND or the
// .ddx/config.yaml beads.backend field selects bd/br).
//
// chaos_test.go and other conformance suites should program against these
// interfaces so additional backends can be exercised by the same tests.
type Backend interface {
	BeadInitializer
	BeadReader
	BeadLifecycle
	BeadEventReader
	BeadEventWriter
	BeadQueries
	BeadDependencyReader
	BeadDependencyWriter
	BeadArchive
	BeadInterchangeReader
	BeadInterchangeWriter

	// Legacy lifecycle mutators retained while caller migration completes.
	Claim(id, assignee string) error
	ClaimWithOptions(id, assignee, session, worktree string) error
	Close(ctx context.Context, id string) error
	CloseWithEvidence(id, sessionID, commitSHA string) error
	SetExecutionCooldown(id string, until time.Time, status, detail, baseRev string) error
	Update(ctx context.Context, id string, mutate func(*Bead)) error
	UpdateWithLifecycleStatus(id string, status string, opts LifecycleTransitionOptions, mutate func(*Bead) error) error
	SetLifecycleStatus(id string, status string, opts LifecycleTransitionOptions) error
	Unclaim(id string) error
	RequestCancel(id string) (bool, error)
	Reopen(id string, reason string, appendNotes string) error
}

// TD-027 foundation interfaces. These are additive and intentionally mirror
// the live Store-backed surface used by callers in this bead slice.
type BeadInitializer interface {
	Init(ctx context.Context) error
}

type BeadReader interface {
	ReadAll(ctx context.Context) ([]Bead, error)
	ReadAllFiltered(ctx context.Context, pred func(Bead) bool) ([]Bead, error)
	Get(ctx context.Context, id string) (*Bead, error)
}

type BeadLifecycle interface {
	Create(ctx context.Context, b *Bead) error
	Apply(id string, op Operation) error
}

type BeadEventReader interface {
	Events(id string) ([]BeadEvent, error)
	EventsByKind(id, kind string) ([]BeadEvent, error)
}

type BeadEventWriter interface {
	AppendEvent(id string, event BeadEvent) error
}

type BeadQueries interface {
	List(status, label string, where map[string]string) ([]Bead, error)
	Ready() ([]Bead, error)
	Blocked() ([]Bead, error)
	ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error)
	ProposedOperatorAttention() ([]Bead, error)
	NeedsHuman() ([]Bead, error)
	ExternalBlocked() ([]Bead, error)
	DependencyWaiting() ([]Bead, error)
	BlockedAll() ([]BlockedBead, error)
	Status() (*StatusCounts, error)
}

type BeadDependencyReader interface {
	DepTree(ctx context.Context, rootID string) (string, error)
}

type BeadDependencyWriter interface {
	DepAdd(ctx context.Context, id, depID string) error
	DepRemove(ctx context.Context, id, depID string) error
}

type BeadArchive interface {
	Archive(ctx context.Context, policy ArchivePolicy) ([]string, error)
	Migrate(ctx context.Context) (MigrateStats, error)
}

type BeadInterchangeReader interface {
	ExportTo(ctx context.Context, w io.Writer) error
}

type BeadInterchangeWriter interface {
	Import(ctx context.Context, source, filePath string) (int, error)
}

type ReadOnlyBackend interface {
	BeadInitializer
	BeadReader
	BeadEventReader
	BeadQueries
	BeadDependencyReader
	BeadInterchangeReader
}

// LifecycleSubscriber is the parallel subscription surface from TD-027.
type LifecycleSubscriber interface {
	SubscribeLifecycle(ctx context.Context, projectID string) (<-chan LifecycleEvent, func(), error)
}

// OperationApplier is an optional fast path for RawBackend implementations
// that can preserve specialized mutation behavior.
type OperationApplier interface {
	Apply(ctx context.Context, id string, op Operation) error
}

// BackendType constants
const (
	BackendJSONL = "jsonl"
	BackendBD    = "bd"
	BackendBR    = "br"
)

const DefaultCollection = "beads"

package bead

import (
	"go/ast"
	"go/parser"
	"go/token"
	"os"
	"path/filepath"
	"reflect"
	"runtime"
	"sort"
	"strings"
	"testing"

	"github.com/stretchr/testify/require"
)

// callerMigrationRoots are the caller directories named in the bead contract.
// The scanner focuses on production code in those trees plus the singled-out
// attempt_test.go file that the bead description called out explicitly.
var callerMigrationRoots = []string{
	"cli/cmd",
	"cli/internal/agent",
	"cli/internal/server",
	"cli/internal/escalation",
	"cli/internal/agentmetrics",
	"cli/internal/attemptmetrics",
	"cli/internal/processmetrics",
	"cli/internal/exec",
}

// callerMigrationDocumentedExceptions are the file-level exceptions called out
// by TD-027 for the storage layer. They are kept as a separate allowlist so the
// scanner can ignore them if the search surface expands, and the allowlist stays
// pinned to the documented exceptions instead of ad hoc local edits.
var callerMigrationDocumentedExceptions = map[string]struct{}{
	"cli/internal/bead/bead.go":        {},
	"cli/internal/bead/bead_doctor.go": {},
	"cli/internal/bead/sync.go":        {},
}

// callerMigrationSpecialTestFile is the one test file the bead description
// explicitly named in the caller migration surface.
const callerMigrationSpecialTestFile = "cli/internal/agent/try/attempt_test.go"

func callerMigrationRepoRoot(t *testing.T) string {
	t.Helper()
	_, file, _, ok := runtime.Caller(0)
	require.True(t, ok, "runtime.Caller failed")
	root, err := filepath.Abs(filepath.Join(filepath.Dir(file), "..", "..", ".."))
	require.NoError(t, err)
	return root
}

func callerMigrationAllowlistPaths() []string {
	paths := make([]string, 0, len(callerMigrationDocumentedExceptions))
	for path := range callerMigrationDocumentedExceptions {
		paths = append(paths, path)
	}
	sort.Strings(paths)
	return paths
}

func callerMigrationIsAllowed(path string) bool {
	_, ok := callerMigrationDocumentedExceptions[path]
	return ok
}

func callerMigrationIsScanTarget(path string) bool {
	if path == callerMigrationSpecialTestFile {
		return true
	}
	if strings.HasSuffix(path, "_test.go") {
		return false
	}
	for _, root := range callerMigrationRoots {
		if path == root || strings.HasPrefix(path, root+"/") {
			return true
		}
	}
	return false
}

func callerMigrationConcreteStoreRefs(t *testing.T, path string) []string {
	t.Helper()
	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, path, nil, 0)
	require.NoError(t, err, "parse %s", path)

	var refs []string
	ast.Inspect(file, func(n ast.Node) bool {
		star, ok := n.(*ast.StarExpr)
		if !ok {
			return true
		}
		sel, ok := star.X.(*ast.SelectorExpr)
		if !ok {
			return true
		}
		pkgIdent, ok := sel.X.(*ast.Ident)
		if !ok || pkgIdent.Name != "bead" || sel.Sel == nil || sel.Sel.Name != "Store" {
			return true
		}
		refs = append(refs, fset.Position(star.Pos()).String())
		return true
	})
	return refs
}

// TestCallerMigration_NoConcreteStore ensures the caller surface in the bead
// contract no longer keeps concrete *bead.Store types in the named directories.
// The only test file scanned is the one explicitly called out in the bead
// description.
func TestCallerMigration_NoConcreteStore(t *testing.T) {
	root := callerMigrationRepoRoot(t)

	var violations []string
	for _, relRoot := range callerMigrationRoots {
		absRoot := filepath.Join(root, relRoot)
		err := filepath.WalkDir(absRoot, func(path string, d os.DirEntry, err error) error {
			if err != nil {
				return err
			}
			if d.IsDir() {
				return nil
			}
			if filepath.Ext(path) != ".go" {
				return nil
			}

			rel, relErr := filepath.Rel(root, path)
			if relErr != nil {
				rel = path
			}
			rel = filepath.ToSlash(rel)

			if !callerMigrationIsScanTarget(rel) {
				return nil
			}
			if callerMigrationIsAllowed(rel) {
				return nil
			}

			for _, ref := range callerMigrationConcreteStoreRefs(t, path) {
				violations = append(violations, rel+" @ "+ref)
			}
			return nil
		})
		require.NoError(t, err, "walk %s", relRoot)
	}

	if len(violations) > 0 {
		sort.Strings(violations)
		t.Fatalf("concrete *bead.Store usage remains in the caller surface:\n  %s", strings.Join(violations, "\n  "))
	}
}

// TestCallerMigration_AllowlistMatchesDocumentedExceptions keeps the allowlist
// pinned to the TD-027 file-level exceptions rather than allowing local drift.
func TestCallerMigration_AllowlistMatchesDocumentedExceptions(t *testing.T) {
	got := callerMigrationAllowlistPaths()
	want := []string{
		"cli/internal/bead/bead.go",
		"cli/internal/bead/bead_doctor.go",
		"cli/internal/bead/sync.go",
	}
	if !reflect.DeepEqual(got, want) {
		t.Fatalf("caller migration allowlist drifted:\n  got:  %v\n  want: %v", got, want)
	}
}

