// TestInstall_FromEmbedFS_CopiesBootstrapSkill verifies the embed.FS bootstrap
// case: the single shipped `ddx` skill ends up as real files (not symlinks)
// in <projectRoot>/.agents/skills/ddx and <projectRoot>/.claude/skills/ddx.
func TestInstall_FromEmbedFS_CopiesBootstrapSkill(t *testing.T) {
	projectRoot := t.TempDir()

	require.NoError(t, Install(SkillFiles, projectRoot, Options{}))

	for _, parent := range []string{".agents", ".claude"} {
		skillFile := filepath.Join(projectRoot, parent, "skills", "ddx", "SKILL.md")
		info, err := os.Lstat(skillFile)
		require.NoError(t, err, "missing SKILL.md at %s", skillFile)
		assert.Zero(t, info.Mode()&os.ModeSymlink, "SKILL.md must be a real file, not a symlink: %s", skillFile)
		data, err := os.ReadFile(skillFile)
		require.NoError(t, err)
		assert.NotEmpty(t, data, "SKILL.md should be non-empty")
	}
}

// TestInstall_BrokenTarballSymlinkRecovery verifies that when the source's
// .agents/skills/<skill> entry is a broken symlink (typical of a
// mis-extracted plugin tarball), Install falls back to <source>/skills/<skill>
// and writes real files to the destination.
func TestInstall_BrokenTarballSymlinkRecovery(t *testing.T) {
	if runtime.GOOS == "windows" {
		t.Skip("symlinks not reliable on windows")
	}

	source := t.TempDir()
	// Real content lives at <source>/skills/foo
	require.NoError(t, os.MkdirAll(filepath.Join(source, "skills", "foo"), 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(source, "skills", "foo", "SKILL.md"), []byte("# foo"), 0o644))

	// Plugin-style entry with a BROKEN symlink.
	require.NoError(t, os.MkdirAll(filepath.Join(source, ".agents", "skills"), 0o755))
	brokenLink := filepath.Join(source, ".agents", "skills", "foo")
	require.NoError(t, os.Symlink("../../skills/foo-does-not-exist", brokenLink))

	projectRoot := t.TempDir()
	require.NoError(t, Install(os.DirFS(source), projectRoot, Options{}))

	for _, parent := range []string{".agents", ".claude"} {
		dest := filepath.Join(projectRoot, parent, "skills", "foo", "SKILL.md")
		info, err := os.Lstat(dest)
		require.NoError(t, err, "fallback content missing at %s", dest)
		assert.Zero(t, info.Mode()&os.ModeSymlink, "destination must be a real file: %s", dest)
		data, err := os.ReadFile(dest)
		require.NoError(t, err)
		assert.Equal(t, "# foo", string(data))
	}
}

// TestInstall_RejectsPathTraversal verifies that '..', absolute, and
// symlink-escape inputs return an error before any write.
func TestInstall_RejectsPathTraversal(t *testing.T) {
	t.Run("dotdot skill name", func(t *testing.T) {
		// fstest.MapFS allows planting a directory named "..".
		src := fstest.MapFS{
			"../bad/SKILL.md": &fstest.MapFile{Data: []byte("# bad")},
		}
		projectRoot := t.TempDir()
		err := Install(src, projectRoot, Options{})
		require.Error(t, err)
		// Nothing should have been written.
		_, statErr := os.Stat(filepath.Join(projectRoot, ".agents", "skills"))
		assert.True(t, statErr == nil || os.IsNotExist(statErr), "no skill content should be written")
		// In particular no skill subdir exists.
		assertNoSkillsWritten(t, projectRoot)
	})

	t.Run("absolute path projectRoot", func(t *testing.T) {
		// Empty projectRoot is rejected.
		err := Install(SkillFiles, "", Options{})
		require.Error(t, err)
	})

	t.Run("sveltekit spread syntax allowed", func(t *testing.T) {
		// [...param] in SvelteKit catch-all routes contains "..." which includes ".."
		// as a substring — must NOT be treated as path traversal.
		src := fstest.MapFS{
			"myskill/SKILL.md": &fstest.MapFile{Data: []byte("# myskill")},
			"myskill/routes/nodes/[nodeId]/documents/[...path]/+page.svelte": &fstest.MapFile{Data: []byte("content")},
		}
		projectRoot := t.TempDir()
		err := Install(src, projectRoot, Options{})
		require.NoError(t, err, "[...path] spread syntax must not trigger path-traversal rejection")
	})

	t.Run("symlink escape via .agents/skills", func(t *testing.T) {
		if runtime.GOOS == "windows" {
			t.Skip("symlinks not reliable on windows")
		}
		projectRoot := t.TempDir()
		outside := t.TempDir()
		// Plant a symlink at projectRoot/.agents/skills pointing OUTSIDE projectRoot.
		require.NoError(t, os.MkdirAll(filepath.Join(projectRoot, ".agents"), 0o755))
		require.NoError(t, os.Symlink(outside, filepath.Join(projectRoot, ".agents", "skills")))

		err := Install(SkillFiles, projectRoot, Options{})
		require.Error(t, err)
		// And confirm nothing was written into the outside dir.
		entries, _ := os.ReadDir(outside)
		assert.Empty(t, entries, "Install must not write outside projectRoot")
	})
}

func assertNoSkillsWritten(t *testing.T, projectRoot string) {
	t.Helper()
	for _, parent := range []string{".agents", ".claude"} {
		dir := filepath.Join(projectRoot, parent, "skills")
		entries, err := os.ReadDir(dir)
		if errors.Is(err, fs.ErrNotExist) {
			continue
		}
		require.NoError(t, err)
		for _, e := range entries {
			t.Errorf("unexpected skill entry written: %s/%s", dir, e.Name())
		}
	}
}

// TestInstall_PreExistingSymlinkRemovedUnconditionally verifies that pre-existing
// SYMLINK destinations are removed and rewritten as real files even when
// Force=false. This heals migrations from the symlinked-home model.
func TestInstall_PreExistingSymlinkRemovedUnconditionally(t *testing.T) {
	if runtime.GOOS == "windows" {
		t.Skip("symlinks not reliable on windows")
	}
	projectRoot := t.TempDir()

	// Plant a symlink at .agents/skills/ddx pointing somewhere arbitrary inside projectRoot.
	someTarget := filepath.Join(projectRoot, "elsewhere")
	require.NoError(t, os.MkdirAll(someTarget, 0o755))
	require.NoError(t, os.MkdirAll(filepath.Join(projectRoot, ".agents", "skills"), 0o755))
	linkPath := filepath.Join(projectRoot, ".agents", "skills", "ddx")
	require.NoError(t, os.Symlink(someTarget, linkPath))

	// Force=false — symlinks must still be replaced.
	require.NoError(t, Install(SkillFiles, projectRoot, Options{Force: false}))

	info, err := os.Lstat(linkPath)
	require.NoError(t, err)
	assert.Zero(t, info.Mode()&os.ModeSymlink, "pre-existing symlink should be replaced with a real dir")
	assert.True(t, info.IsDir())
	skillFile := filepath.Join(linkPath, "SKILL.md")
	_, err = os.Stat(skillFile)
	require.NoError(t, err)
}

// TestInstall_ForceFalseSkipsRealDir verifies that pre-existing real-file
// skill directories are preserved when Force=false (per-skill skip).
func TestInstall_ForceFalseSkipsRealDir(t *testing.T) {
	projectRoot := t.TempDir()
	skillDir := filepath.Join(projectRoot, ".agents", "skills", "ddx")
	require.NoError(t, os.MkdirAll(skillDir, 0o755))
	customFile := filepath.Join(skillDir, "SKILL.md")
	require.NoError(t, os.WriteFile(customFile, []byte("# user-customized"), 0o644))

	require.NoError(t, Install(SkillFiles, projectRoot, Options{Force: false}))

	data, err := os.ReadFile(customFile)
	require.NoError(t, err)
	assert.Equal(t, "# user-customized", string(data), "Force=false must not overwrite real-file skill dir")
}

// Package serverreg provides fire-and-forget project registration with the
// ddx-server. CLI commands call TryRegisterAsync so the server always has an
// up-to-date project list. If no server is reachable the call is silently
// discarded — the CLI never depends on the server being available.
package serverreg

import (
	"bytes"
	"crypto/tls"
	"encoding/json"
	"net/http"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"time"
)

const defaultServerURL = "https://localhost:7743"

var goTestSegmentRegexp = regexp.MustCompile(`/Test[A-Z][^/]*\d+/`)

// TryRegisterAsync fires off a project registration in a background goroutine
// and returns immediately. Errors are silently discarded.
func TryRegisterAsync(projectPath string) {
	if isTransientProjectPath(projectPath) {
		return
	}
	url := resolveServerURL()
	if url == "" {
		return
	}
	go register(url, projectPath)
}

func isTransientProjectPath(path string) bool {
	if path == "" {
		return false
	}
	if hasPathPrefix(path, "/tmp") ||
		hasPathPrefix(path, "/private/tmp") ||
		hasPathPrefix(path, "/var/tmp") ||
		hasPathPrefix(path, "/var/folders") ||
		hasPathPrefix(path, os.TempDir()) {
		return true
	}
	if home, err := os.UserHomeDir(); err == nil && home != "" {
		if hasPathPrefix(path, filepath.Join(home, "tmp")) ||
			hasPathPrefix(path, filepath.Join(home, ".cache", "fleet-tmp")) ||
			filepath.Clean(path) == filepath.Join(home, "Projects") {
			return true
		}
	}
	if strings.Contains(path, "/.cache/fleet-tmp/") ||
		strings.Contains(path, "/ddx-cmd-tests-") ||
		strings.Contains(path, "/.ddx-exec-wt/") ||
		strings.Contains(path, "/.ddx-external-workers/") ||
		strings.Contains(path, "/.claude/worktrees/") ||
		strings.Contains(path, "/.agents/worktrees/") ||
		(strings.Contains(path, "/runs/") && filepath.Base(path) == "workspace") ||
		strings.HasPrefix(filepath.Base(path), ".execute-bead-wt-") {
		return true
	}
	probe := path
	if !strings.HasPrefix(probe, "/") {
		probe = "/" + probe
	}
	if !strings.HasSuffix(probe, "/") {
		probe += "/"
	}
	return goTestSegmentRegexp.MatchString(probe)
}

func hasPathPrefix(path, prefix string) bool {
	if path == "" || prefix == "" {
		return false
	}
	cleanPath := filepath.Clean(path)
	cleanPrefix := filepath.Clean(prefix)
	if cleanPath == cleanPrefix {
		return true
	}
	return strings.HasPrefix(cleanPath, cleanPrefix+string(filepath.Separator))
}

func register(serverURL, projectPath string) {
	body, err := json.Marshal(map[string]string{"path": projectPath})
	if err != nil {
		return
	}

	client := &http.Client{
		Timeout: 500 * time.Millisecond,
		// Accept self-signed certs — the server uses an auto-generated cert.
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
		},
	}

	req, err := http.NewRequest(http.MethodPost, serverURL+"/api/projects/register", bytes.NewReader(body))
	if err != nil {
		return
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := client.Do(req)
	if err != nil {
		return
	}
	_ = resp.Body.Close()
}

// resolveServerURL returns, in order of preference:
//  1. DDX_SERVER_URL environment variable
//  2. URL from ~/.local/share/ddx/server.addr
//  3. https://localhost:7743 (default)
func resolveServerURL() string {
	if u := os.Getenv("DDX_SERVER_URL"); u != "" {
		return u
	}
	if u := readAddrFile(); u != "" {
		return u
	}
	return defaultServerURL
}

func readAddrFile() string {
	type addrFile struct {
		URL string `json:"url"`
	}
	dir := addrDir()
	data, err := os.ReadFile(filepath.Join(dir, "server.addr"))
	if err != nil {
		return ""
	}
	var af addrFile
	if err := json.Unmarshal(data, &af); err != nil {
		return ""
	}
	return af.URL
}

func addrDir() string {
	if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
		return filepath.Join(xdg, "ddx")
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return filepath.Join("/tmp", "ddx")
	}
	return filepath.Join(home, ".local", "share", "ddx")
}

package cmd

import (
	"os"
	"path/filepath"
	"testing"

	"github.com/stretchr/testify/require"
)

// makeWorkDirWithLegacySymlink creates a temp workdir containing a legacy DDx
// skill symlink under .agents/skills/, which causes full-scope doctor to exit
// non-zero.
func makeWorkDirWithLegacySymlink(t *testing.T) string {
	t.Helper()
	workDir := t.TempDir()
	agentSkillsDir := filepath.Join(workDir, ".agents", "skills")
	require.NoError(t, os.MkdirAll(agentSkillsDir, 0o755))
	require.NoError(t, os.Symlink("/nonexistent/old-global-path/ddx", filepath.Join(agentSkillsDir, "ddx")))
	return workDir
}

// TestDoctorScopedToConfigChange asserts that `ddx doctor --paths .ddx.yml`
// only runs config-related checks and exits 0 when other repo state (e.g.
// legacy skill symlinks) would have failed a full-scope doctor. [ddx-777f4a09 AC1]
func TestDoctorScopedToConfigChange(t *testing.T) {
	workDir := makeWorkDirWithLegacySymlink(t)

	factory := NewCommandFactory(workDir)
	_, err := executeWithStdoutCapture(t, factory.NewRootCommand(), "doctor", "--paths", ".ddx.yml")
	require.NoError(t, err, "doctor --paths .ddx.yml must exit 0 even when legacy symlinks are present")
}

// TestDoctorScopedToResourceChange asserts that `ddx doctor --paths templates/foo`
// only runs resource-related checks and exits 0 when legacy skill symlinks would
// have failed a full-scope doctor. [ddx-777f4a09 AC2]
func TestDoctorScopedToResourceChange(t *testing.T) {
	workDir := makeWorkDirWithLegacySymlink(t)

	for _, path := range []string{
		"templates/example.md",
		"patterns/coding-style.md",
		"prompts/review.md",
	} {
		t.Run(path, func(t *testing.T) {
			factory := NewCommandFactory(workDir)
			_, err := executeWithStdoutCapture(t, factory.NewRootCommand(), "doctor", "--paths", path)
			require.NoError(t, err, "doctor --paths %s must exit 0 even when legacy symlinks are present", path)
		})
	}
}

// TestDoctorFullScopeStillFails is a regression guard: `ddx doctor` with no
// --paths argument must still surface the legacy-symlink finding. [ddx-777f4a09 AC3]
func TestDoctorFullScopeStillFails(t *testing.T) {
	workDir := makeWorkDirWithLegacySymlink(t)

	factory := NewCommandFactory(workDir)
	cmd := factory.NewRootCommand()
	cmd.SetArgs([]string{"doctor"})
	err := cmd.Execute()
	if err == nil {
		t.Fatal("expected non-zero exit from full-scope doctor with legacy symlinks, got nil")
	}
}

// TestDoctorHookPathsDoesNotInvokeFullScope simulates the lefthook ddx-validate
// pre-commit hook passing a space-separated staged path list to --paths. Confirms
// that mixed staged files (config + resource) do not trigger the full-scope
// legacy-symlink check. [ddx-777f4a09 AC4]
func TestDoctorHookPathsDoesNotInvokeFullScope(t *testing.T) {
	workDir := makeWorkDirWithLegacySymlink(t)

	// Simulate the hook passing staged paths including both .ddx.yml and a template.
	factory := NewCommandFactory(workDir)
	output, err := executeWithStdoutCapture(t, factory.NewRootCommand(),
		"doctor", "--paths", ".ddx.yml templates/example.md")
	require.NoError(t, err, "hook-style --paths with multiple staged files must not invoke full-scope doctor")
	require.NotContains(t, output, "Global Install (", "scoped doctor must not report install topology")
	require.NotContains(t, output, "Project Install (", "scoped doctor must not report install topology")
}

// TestDoctorScopedSkillValidationIgnoresInstallLayer asserts that
// `ddx doctor --paths <skill-file>` exits 0 regardless of whether the ddx
// skill is installed globally or project-locally. The ddx-validate pre-commit
// hook must not run install-layer-sensitive checks when only skill files are
// staged. [ddx-4c58ea3e AC4]
func TestDoctorScopedSkillValidationIgnoresInstallLayer(t *testing.T) {
	for _, tc := range []struct {
		name            string
		globalInstalled bool
	}{
		{name: "no_global_install", globalInstalled: false},
		{name: "global_install", globalInstalled: true},
	} {
		t.Run(tc.name, func(t *testing.T) {
			workDir := makeWorkDirWithLegacySymlink(t)
			xdgDir := t.TempDir()
			t.Setenv("XDG_DATA_HOME", xdgDir)

			if tc.globalInstalled {
				globalPluginDir := filepath.Join(xdgDir, "ddx", "global", "plugins", "ddx")
				if err := os.MkdirAll(globalPluginDir, 0o755); err != nil {
					t.Fatalf("mkdir global plugin dir: %v", err)
				}
			}

			for _, stagingPath := range []string{
				".ddx/plugins/ddx/skills/ddx/SKILL.md",
				"skills/ddx/SKILL.md",
			} {
				t.Run(stagingPath, func(t *testing.T) {
					factory := NewCommandFactory(workDir)
					output, err := executeWithStdoutCapture(t, factory.NewRootCommand(),
						"doctor", "--paths", stagingPath)
					require.NoError(t, err,
						"doctor --paths %s must exit 0 regardless of install layer; legacy symlinks must not be checked for skill-file-only staged sets",
						stagingPath,
					)
					require.NotContains(t, output, "Global Install (", "skill-file-only scoped doctor must not report install topology")
					require.NotContains(t, output, "Project Install (", "skill-file-only scoped doctor must not report install topology")
				})
			}
		})
	}
}

