func TestCategorizeStagedPaths_Resource(t *testing.T) {
	for _, p := range []string{"templates/foo.md", "patterns/bar.md", "prompts/baz.md"} {
		cats := categorizeStagedPaths([]string{p})
		if !cats["resource"] {
